var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"우선, 실행위원장으로서 내일 학원제의 준비 상황을 보고하자면……","JPN":"さて、まずは学園祭実行委員長の俺から\\n明日に控えた学園祭の進捗状況を報告する。","ENG":"First and foremost, as the head of the executive committee, I'll report on the status of preparations for tomorrow's festival...","TWN":"首先，就由身為執行委員長的我，來跟大家報告學園祭的準備情形……"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"전체적으로는 순조로운 편이지만, 현재 몇몇 동아리로부터 클레임이 접수된 상태야.","JPN":"全体的には順調だが、\\nいくつか苦情やトラブルの報告が寄せられている。","ENG":"Everything is going smoothly overall, but a few clubs have filed some complaints.","TWN":"整體而言是順利的，只是有幾個社團提出一些訴求。"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"그렇군요. 임원들이 각각 분담해서 해결하면 좋겠네요.","JPN":"なるほど。\\n役員で各トラブルを分担して解決を図りましょうか。","ENG":"I see. The members can each take charge of one and resolve the issues.","TWN":"是嗎？那就由幹部們一起分頭處理吧。"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"흥, 보나마나 쓰잘 데 없는 요청이겠지.","JPN":"ふん、どうせくだらない文句ばかりでしょう。","ENG":"Hmph. I bet it's just another stupid request.","TWN":"哼，想也知道是無理的要求。"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TAPIR_NPC_GEASS_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"TAPIR_NPC_GEASS_NULL","text":{"KOREA":"나이엘 양. 그러지말고 이야기를 들어봐요.","JPN":"ナイエルさん、まずは話を聞かないと。","ENG":"Naielle, please try to listen to them at least.","TWN":"奈爾，你別這樣，先把話聽完。"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TAPIR_NPC_GEASS_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L11_1","type":"dialog","speaker":"KALLEN_NPC_GEASS_NULL","text":{"KOREA":"그래서? 무슨 클레임인데?","JPN":"それで？　どんな苦情が来ているの？","ENG":"So? What are their complaints?","TWN":"所以呢？是什麼樣的訴求？"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KALLEN_NPC_GEASS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHIRLEY_NPC_GEASS_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"먼저 수영부에서 클레임을 보내왔어.","JPN":"まずは、水泳部からの苦情だな。","ENG":"First, from the swim club.","TWN":"首先是游泳部的訴求。"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"수영부에서는 카페를 준비하고 있는데, 카페 주변에서 원인 모를 악취가 난다고 해.","JPN":"水泳部はカフェを準備しているが、どこからか原因不明の悪臭がしているそうだ。","ENG":"They are preparing to open a cafe, but they keep smelling this awful odor nearby.","TWN":"他們表示，游泳部在籌備開設咖啡廳，但咖啡廳周圍卻發出不明惡臭。"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"이대로는 카페 운영이 어렵다면서 학생회에게 도움을 요청했어.","JPN":"このままではカフェを運営するにあたって支障が出てしまう。","ENG":"They are asking us for help as they claim it will be difficult to run a cafe with the awful smell in the air.","TWN":"這樣會導致咖啡廳經營上的困難，因此希望學生會介入幫忙。"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"뭐야 뭘 그런 걸 가지고! 애초에 본인들이 수영장 청소를 똑바로 안 했겠지!","JPN":"何よ、その程度のことで！\\nそもそも本人たちがプールの掃除をきちんとしなかったせいでしょ？","ENG":"That's it?! My guess is that they didn't scrub the pool hard enough!","TWN":"他們還真敢說！肯定是他們自己沒有把游泳池打掃乾淨吧！"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"TAPIR_NPC_GEASS_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"SHIRLEY_NPC_GEASS_NULL","text":{"KOREA":"무슨 소리야, 나이엘. 우리가 얼마나 수영장 관리를 열심히 하는데?","JPN":"なに言ってるの、ナイエル。\\n普段、私たちはちゃんと管理してるんだから。","ENG":"That's not true, Naielle. We take pool maintenance very seriously!","TWN":"你少胡說，奈爾。我們可是很認真在管理游泳池的！"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHIRLEY_NPC_GEASS_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SHIRLEY_NPC_GEASS_NULL","text":{"KOREA":"애초에 우리 학생들이 다 같이 쓰는 수영장이잖아, 청소도 매일같이 하고 있고.","JPN":"なんてたって、自分たちで使うプールだからね。\\n掃除だって毎日きちんとしてるよ。","ENG":"It's for everyone to use, so we clean it daily.","TWN":"而且游泳池不是大家一起共用的嗎？我們每天都有打掃。"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHIRLEY_NPC_GEASS_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"흠. 그러고보니 셜리 넌 수영부랑 학생회를 겸임하고 있었지? ","JPN":"ふむ。シャーリーは水泳部と生徒会を兼任していたな。","ENG":"Hmm. Shirley, you're also a member of the swim club, right? ","TWN":"嗯，這麼說來，夏麗，游泳部和學生會你都有加入吧？"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"그럼 그쪽 사정을 잘 알겠네. 수영부 건을 부탁해도 될까?","JPN":"なら、そちらの事情には詳しいはずだ。\\n水泳部の件はシャーリーに頼んでもいいか？","ENG":"Then you'll know their situation better than any of us. Can you take care of this one?","TWN":"那你應該很清楚情況，游泳部的事可以交給你嗎？"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SHIRLEY_NPC_GEASS_NULL","text":{"KOREA":"응, 알았어! 나한테 맡겨!","JPN":"うん、わかった！　私に任せて！","ENG":"Okay! Leave it to me!","TWN":"嗯，沒問題！我來處理！"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHIRLEY_NPC_GEASS_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"다음은 사진부에서 온 건이야. 전시에 관해 문제가 있다고 하는군.","JPN":"次は写真部からだ。展示に関してのトラブルだな","ENG":"Next is from the photography club. They seem to be having a problem regarding their exhibition.","TWN":"接下來是攝影部的訴求，是與展出有關的問題。"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"전시 일정을 다시 조율해달라고 하는데…… 아마, 이쪽은 문제가 좀 복잡할 지도 몰라.","JPN":"展示日程を再度調整してほしいとのことだが……\\nおそらくこちらは解決には、やや手こずるだろう。","ENG":"They want us to reschedule the exhibition, but... I think it'll be more complicated than that.","TWN":"他們希望可以調整展出的日期……這個問題可能會有點複雜。"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"KALLEN_NPC_GEASS_NULL","text":{"KOREA":"응? 어째서?","JPN":"うん？　どうして？","ENG":"Hmm? How so?","TWN":"嗯？為什麼？"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KALLEN_NPC_GEASS_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SHIRLEY_NPC_GEASS_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"사진부와 미술부는 학원제 때마다 전시관을 공유하거든. 그래서 서로 트러블이 잦아.","JPN":"写真部と美術部は学園祭の時、毎回展示会場を共有する。\\nそのためトラブルが起きることが多いんだ。","ENG":"The photography club and art club have shared the gallery every festival. So those two are always bickering with each other.","TWN":"攝影部和美術部每次在學園祭時都會共用展覽館，彼此常常發生衝突。"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"하지만 전시 공간은 한정되어 있어. 학생회에서도 모든 요구를 들어줄 수는 없고.","JPN":"しかし、展示スペースは限られている。\\n生徒会とはいえ、すべての要求を聞き入れることは出来ない。","ENG":"However, the gallery space is limited, and we can't say yes to every request.","TWN":"不過展示空間就那麼大，學生會也不可能滿足所有的要求。"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"흥! 그깟 아마추어 전시를 누가 본다고! 그냥 무시해버려!","JPN":"ふん！　あんなアマチュアの展示に需要あんの？　無視しちゃえば？","ENG":"Hmph! Who cares about an exhibition by amateurs? Just ignore them!","TWN":"哼！那種業餘的展覽誰要看！不用理他們啦！"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"TAPIR_NPC_GEASS_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"KALLEN_NPC_GEASS_NULL","text":{"KOREA":"그래도 한 해 동안의 결과물을 전시하는 자리잖아? 되도록이면 둘 다 좋은 조건으로 전시하고 싶겠지.","JPN":"でも一年間の成果を披露する場じゃない？\\nどちらも出来るだけ良い展示にしたいだろうしね。","ENG":"But they've been working on it all year, right? I get why they both want a good deal.","TWN":"但那是他們辛苦一年的成果，當然會想在好的環境下展出吧？"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KALLEN_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"옳은 말이야, 카렌.","JPN":"そのとおりだ、カレン。","ENG":"Exactly, Kallen.","TWN":"你說的沒錯，卡蓮。"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"아마 힘든 일이 될 수도 있어. 이 클레임은 네가 맡아 줄 수 있을까?","JPN":"少々荒事になるかもしれない。この件、お前に任せてもいいか？","ENG":"It might be a lot to handle, but could you take charge of this one?","TWN":"這件事可能不好處理，可以交給你辦嗎？"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"KALLEN_NPC_GEASS_NULL","text":{"KOREA":"그럴지도. 자신은 없지만 일단 알겠어.","JPN":"そうね。自信はないけど了解よ。","ENG":"Perhaps it will be. But okay. I'll do what I can.","TWN":"可以吧，雖然沒什麼信心，但我就試試看吧。"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KALLEN_NPC_GEASS_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"마지막은 연극부에서 온 부탁인데…….","JPN":"最後は演劇部からのお願いだな……","ENG":"And lastly, there's a complaint from the theater club...","TWN":"最後是戲劇部的訴求……"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"회장, 연극부에서는 회장에게 직접 도움을 요청했어요.","JPN":"会長。演劇部から会長の助力を請う依頼がありました。","ENG":"Yen, they specifically asked for you.","TWN":"會長，戲劇部希望會長可以親自幫忙。"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"네? 저를요?","JPN":"はい？　私に、ですか？","ENG":"Huh? Me?","TWN":"什麼？我嗎？"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"네. 이유는 모르겠지만, 연극에 회장의 검술 실력이 필요하다고 하네요.","JPN":"はい。理由はわかりませんが、演劇に会長の剣術が必要だそうです。","ENG":"Correct. I don't know why, but your sword skills are required in their play.","TWN":"是，具體原因不清楚，但他們說戲裡需要會長精湛的劍術。"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"검술……? 검술과 연극이 무슨 관련이 있는지 모르겠군요.","JPN":"剣術……？\\n剣術と演劇にどのような関係があるのか、まったくわかりませんね。","ENG":"My sword skills...? I don't see how those two are connected.","TWN":"劍術……？我想不透劍術和演戲有什麼關聯呢。"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"그렇군요. 연극부에게 구체적인 사유를 들은 것은 아니니…… 이 건은 거절할까요?","JPN":"そうですね。直接、演劇部に詳しい話を聞いてみないことには……\\nどうします？　断りますか？","ENG":"I see. Since the theater club didn't ask for anything specific... shall we discard this one, then?","TWN":"是啊，而且戲劇部也沒詳細說明……要拒絕嗎？"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"아니요. 학생이 곤란해하고있다면, 그 목소리에 귀를 기울이는 것이 학생회의 역할입니다. 이야기를 들어보도록 하죠.","JPN":"いいえ。生徒が困っているのなら、何とかするのが生徒会の役目。\\n時間を作って話を聞いてみましょう。","ENG":"No. If the students are having trouble with something, it is the Student Council's job to listen to their needs. I'll go and see what it's about.","TWN":"不，既然學生有煩惱，學生會會長的責任就是要傾聽他們的聲音。我親自去一趟吧。"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"잠깐, 를르슈! 란체스터 회장은 바쁜 몸이라구!","JPN":"待って、ルルーシュ！\\nランチェスター会長はめちゃくちゃ忙しいんだよ？","ENG":"Wait, Lelouch! Ms. Lanchester is already busy enough!","TWN":"先等一下，魯路修！蘭賈斯特會長很忙欸！"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"이 세자루의 검이 보이지? 회장만큼은 아니지만, 검술이라면 나도 제법 쓸만하다구?","JPN":"この三本の剣が見えるでしょ？\\n会長ほどじゃないけど、剣術なら私も結構自信があるわ！","ENG":"See the three swords here? I might not be as good as her, but I'm also skilled with swords, you know.","TWN":"有看到這三把劍嗎？雖然我沒有會長那麼厲害，但劍術的話我也是略懂略懂。"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"적극적인 태도는 좋지만, 나이엘.","JPN":"申し出はありがたいがな、ナイエル。","ENG":"Naielle, I like your active participation, but...","TWN":"你這麼積極是很好，"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"너는 따로 해야 할 일이 있을 텐데?","JPN":"お前には自分のやるべき仕事があるだろ？","ENG":"I'm sure you have your own tasks, do you not?","TWN":"但是奈爾，你有別的任務。"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"응? 뭐라고? 내가 따로 해야할 일?","JPN":"え、なに？　私のやるべき仕事って？","ENG":"Hmm? What? I have things to do?","TWN":"蛤？你說什麼？我有別的任務？"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"네? 설마, 잊으신 건가요, 나이엘?","JPN":"うん？　まさか忘れているのですか、ナイエルさん？","ENG":"Huh? Don't tell me you forgot, Naielle.","TWN":"什麼？你該不會忘了吧，奈爾？"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"후야제에서 피울 캠프파이어의 준비는 그해의 학년 대표가 진행하는 것이 관행일 텐데요?","JPN":"後夜祭のキャンプファイヤーの準備は、\\nその年の学年代表が進行するのがしきたりですが。","ENG":"The campfire preparations for the post-festival party. It is tradition that the year's student representative host it.","TWN":"按照慣例，當年度的學生代表要在慶功宴上負責升營火。"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"에, 에엑……? 올해의 캠프파이어 담당이 나라고?","JPN":"え、ええっ！？\\n今年のキャンプファイヤー担当が私ですって！？","ENG":"E-eck...? Is that supposed to be my duty?","TWN":"欸欸欸……？今年是我負責升營火喔？"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"타피르 선배! 선배도 학년 대표잖아! 왜 그런 중요한 이야기를 나한테 안 해준 건데?","JPN":"タピル先輩！　先輩も学年代表でしょ！\\nなんでそんな大事な話を私に言わないのよ！","ENG":"Tapir! You're also this year's student representative! Why didn't you tell me about this?","TWN":"達爾前輩！你不也是學生代表嗎？這麼重要的事你怎麼沒跟我說？"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"TAPIR_NPC_GEASS_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L20_1","type":"dialog","speaker":"TAPIR_NPC_GEASS_NULL","text":{"KOREA":"그, 그렇지만 저도 학년 대표는 올해가 처음이라서…….","JPN":"で、でも僕も学年代表は今年が初めてだったし……","ENG":"B-but it's my first time being a student representative too...","TWN":"話，話是沒錯，但我也是今年才第一次當上學生代表……"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"TAPIR_NPC_GEASS_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L23_1","type":"dialog","speaker":"SHIRLEY_NPC_GEASS_NULL","text":{"KOREA":"뭐야?! 그럼 두 사람 다 여지껏 캠프파이어 준비를 하나도 안 해 놨다는 거야?","JPN":"ええっ！？　それじゃあ2人とも\\nキャンプファイヤーの準備が何もできてないってこと？","ENG":"What?! Then you two did nothing about the campfire?","TWN":"搞什麼？！意思是你們二個到現在都還沒開始準備營火的事嗎？"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KALLEN_NPC_GEASS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHIRLEY_NPC_GEASS_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L24_1","type":"dialog","speaker":"KALLEN_NPC_GEASS_NULL","text":{"KOREA":"큰일이네. 아마 지금부터 준비해도 빠듯할 텐데.","JPN":"大変だね。今から用意してもギリギリになりそう。","ENG":"This isn't good. Even if they start now, it's going to be tight.","TWN":"不太妙，就算現在開始準備也有點勉強呢。"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KALLEN_NPC_GEASS_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SHIRLEY_NPC_GEASS_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L27_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"서, 서프라이즈! 아하핫……! 다들 깜짝 놀랐지?","JPN":"ド、ドッキリ大成功！　アハハッ……！　みんな、騙されちゃった？","ENG":"S-surprise! Ah hah hah...! I got you all good, didn't I?","TWN":"Su…Surprise！哈哈哈……！大家嚇到了吧？"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L28_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"설마 올해의 학년 대표가 그렇게 중요한 걸 잊고 있을 리가 없잖아? 안 그래?","JPN":"まさか今年の学年代表が\\nそんな大事なことを忘れてるはずがないでしょ！　ね？　先輩！","ENG":"There's no way the student representative would ever forget something this important! Right?","TWN":"今年的學生代表怎麼可能忘記這麼重要的事呢？大家說是不是？"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"TAPIR_NPC_GEASS_NULL","text":{"KOREA":"나이엘 양! 그게 무슨……?","JPN":"ナイエルさん、それはどういう……？","ENG":"Naielle! What are you–","TWN":"奈爾！你在說什……？"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"TAPIR_NPC_GEASS_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L34_1","type":"dialog","speaker":"TAPIR_NPC_GEASS_NULL","text":{"KOREA":"아얏! 마, 맞아요! 서프라이즈였죠! 아하하.","JPN":"痛っ！　あっ、そ、そうです！　今のはドッキリでした！　アハハハ。","ENG":"Ouch! Y-yup! It was a joke! Ah hah hah.","TWN":"哎呀！沒，沒錯！是Surprise啦！哈哈哈。"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"TAPIR_NPC_GEASS_NULL","face":"UNIT_LAUGH"}}}},{"id":"L35_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"다들 기대하고 있으라구? 다들 깜짝 놀랄 필살기를 보여줄 테니깐!","JPN":"楽しみにしていてね！\\nみんなをビックリさせる必殺技を用意してるから！","ENG":"I hope you're all ready for it. Because we got something incredible to show you!","TWN":"大家敬請期待吧，我會讓你們見識到我厲害的必殺技！"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"TAPIR_NPC_GEASS_NULL","face":"UNIT_LAUGH"}}}},{"id":"L36_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"가자, 타피르 선배! 얼른, 장작부터 준비하자고!","JPN":"行こう、タピル先輩！　さっそく薪から用意するわよ！","ENG":"Let's go, Tapir! C'mon! Let's go get the firewood!","TWN":"走吧，達爾前輩！我們先去準備木柴吧！"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"TAPIR_NPC_GEASS_NULL","face":"UNIT_LAUGH"}}}},{"id":"L37_1","type":"dialog","speaker":"TAPIR_NPC_GEASS_NULL","text":{"KOREA":"켁! 나이엘 양, 그렇게 넥타이를 당기시면……!","JPN":"あっ！　ナイエルさん、そんな乱暴に引っ張らないでください……！","ENG":"Kuh! Naielle, please stop yanking my tie like that...!","TWN":"唔！奈爾，你這樣拉我的領帶，我……！"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"TAPIR_NPC_GEASS_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L40_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"큰 소리 치긴 했어도, 두 사람한테만 맡기기에는 역시 조금 불안하네.","JPN":"自信満々に言っているが、あの二人に任せるのはやはり少し不安だな。","ENG":"Well, they say that, but I feel anxious leaving it up to just those two.","TWN":"雖然他們一副信誓旦旦的樣子，但只交給他們二個還是有點不安。"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SHIRLEY_NPC_GEASS_NULL","text":{"KOREA":"에휴, 어쩔 수 없지. 좀 있다가 우리도 도와주자. 올해 학년 대표가 됐다고 얼마나 좋아했는데.","JPN":"はあ、仕方ないね。後で私たちも協力しますか。\\nナイエルが今年の学年代表に決まった時はすごく喜んで張り切ってたし。","ENG":"Ugh, fine. We'll help them out in a bit. Naielle was so excited to become this year's student representative.","TWN":"哀，真拿他們沒辦法，我們晚一點也去幫忙吧。當上學生代表就開心到忘我。"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KALLEN_NPC_GEASS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHIRLEY_NPC_GEASS_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L44_1","type":"dialog","speaker":"KALLEN_NPC_GEASS_NULL","text":{"KOREA":"맞아, 모두가 도우면 금방 끝날 거야.","JPN":"そうね、みんなで協力したらすぐ終わるはずよ。","ENG":"Yeah, it'll be done in no time if we all chip in.","TWN":"沒錯，大家一起幫忙很快就可以完成的。"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KALLEN_NPC_GEASS_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SHIRLEY_NPC_GEASS_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L46_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"조화로운 모습 보기 좋군요. 그럼 각자 맡은 일이 끝난 뒤 캠프파이어 준비를 돕도록 하죠.","JPN":"協力し合う姿は素晴らしいですね。\\nそれでは、各担当の仕事が終わったらキャンプファイヤーの準備を手伝うことにしましょう。","ENG":"It's nice to see everyone in harmony. Then, after we are all done with our tasks, let's help the two out with the campfire preparations.","TWN":"看到大家這麼團結真好。那就各自忙完交付的任務後，再一起協助準備營火。"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"미나 양? 아까부터 말씀이 없으시네요. 괜찮으세요?","JPN":"ミナさん？　さっきから静かですね、大丈夫ですか？","ENG":"Mina? You haven't said a word. Are you okay?","TWN":"米娜？你怎麼都不說話？還好嗎？"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아, 미안. 나도 모르게 잠깐 딴 생각을 했네.","JPN":"あ、ごめん。ちょっと違うことを考えてた。","ENG":"Oh, sorry. I guess I zoned out again.","TWN":"喔，抱歉，我剛在想別的事。"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"……","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그보다 나는 뭘 도우면 돼?","JPN":"それより、私は何を手伝えばいい？","ENG":"Anyway, is there something I can help with?","TWN":"那我要幫什麼忙呢？"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"아, 그렇지.","JPN":"ああ。そうだな……","ENG":"Oh, right.","TWN":"對，差點忘記。"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"미나, 일단 셜리와 같이 수영부 쪽을 도와주겠어?","JPN":"ミナは、とりあえずシャーリーと一緒に水泳部のフォローをしてくれないか？","ENG":"Mina, could you help Shirley with the swim club issue?","TWN":"米娜，那你可以和夏麗一起協助游泳部嗎？"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"응, 수영부를 도우면 되는 거지? 알겠어.","JPN":"水泳部ね、わかった。","ENG":"Sure. The swim club, right? Got it.","TWN":"嗯，協助游泳部就好嗎？好的。"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SHIRLEY_NPC_GEASS_NULL","text":{"KOREA":"도착했어, 미나. 여기가 수영장이야.","JPN":"着いたよ、ミナ。ここがプールね。","ENG":"We're here, Mina. This is the pool.","TWN":"米娜，到了，這裡就是游泳池。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHIRLEY_NPC_GEASS_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"수영부가 여기서 카페 준비를 하고있다 했다면서? 부원들은 한 명도 없는데?","JPN":"水泳部はここでカフェの準備をしているんだよね？\\nでも、部員が一人もいないよ？","ENG":"So, they're going to operate a cafe here? But where is everyone?","TWN":"游泳部不是說要預備咖啡廳嗎？怎麼一個人都沒有？"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHIRLEY_NPC_GEASS_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SHIRLEY_NPC_GEASS_NULL","text":{"KOREA":"악취 때문에 요리를 할 수가 없어서 대신 실습실에서 준비하고 있대. 그동안 우리가 악취의 원인을 찾아내야 해.","JPN":"悪臭のせいで料理の準備ができないから、家庭科室で準備してるんだって。\\nその間に、私たちが原因を究明して、解決しないと。","ENG":"They said they couldn't cook with the awful stench, so they're all inside the practice room, preparing. Meanwhile, we have to find what's causing the smell.","TWN":"他們說這裡太臭沒辦法準備餐點，所以改到實驗室。\\n趁他們在預備時，我們必須找出惡臭的原因。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHIRLEY_NPC_GEASS_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그렇구나. 듣고 보니 어디서 기름 같은 냄새가 나긴 하네.","JPN":"なるほど。\\n言われてみれば、どこからか油のような臭いがするね。","ENG":"Okay. Come to think of it, I think I smell oil.","TWN":"原來如此，這樣聽起來，應該是某個地方有油的味道吧。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHIRLEY_NPC_GEASS_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"엇? 셜리, 저기 좀 봐! 검은 덩어리들이 물 위에 둥둥 떠다니고 있어!","JPN":"あれ？　シャーリー、あそこを見て！\\n黒い塊が水の上に浮かんでるよ！","ENG":"Huh? Shirley, look over there! There are black blobs floating on the water!","TWN":"嗯？夏麗，你看那裡！有黑黑的東西浮在水面上！"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SHIRLEY_NPC_GEASS_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"SHIRLEY_NPC_GEASS_NULL","text":{"KOREA":"어라? 정말이네? 어제까지만 해도 저런 게 떠다니지 않았었는데…….","JPN":"あっ、本当だ！　普段はあんなもの浮いてないのに……","ENG":"Oh? You're right! Those weren't there yesterday...","TWN":"喔？真的欸，昨天還沒有的……"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SHIRLEY_NPC_GEASS_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L20_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"어쩌면 이 냄새는 저 기름 덩어리 때문에 났던 걸지도 몰라!","JPN":"もしかすると、この臭いはあの油の塊のせいかもしれない！","ENG":"Maybe that's the cause of the stench!","TWN":"臭味很有可能就是從汙油漬發出來的！"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHIRLEY_NPC_GEASS_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"SHIRLEY_NPC_GEASS_NULL","text":{"KOREA":"응. 그럼 먼저 기름을 걷어내자!","JPN":"うん。とりあえず油を回収しよう！","ENG":"Okay. Let's scoop them out!","TWN":"嗯，先把汙油漬撈出來吧！"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHIRLEY_NPC_GEASS_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L22_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"점점 기름이 퍼져 나가고 있어! 빨리 시작하자.","JPN":"どんどん油が広がっていくよ！　早くいかないと！","ENG":"The oil's spreading! We need to act fast!","TWN":"油漬污染的範圍越來越大了！我們快開始吧！"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SHIRLEY_NPC_GEASS_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L24_1","type":"dialog","speaker":"SHIRLEY_NPC_GEASS_NULL","text":{"KOREA":"잠깐, 미냐야! 너 설마 그 차림으로 물 속에 들어갈 생각이야?","JPN":"待って、ミナ！　その格好でプールに入る気なの？","ENG":"Wait, Mina! You're not thinking of going in the pool like that, right?","TWN":"米娜你先等一下！你該不會是要直接穿這身衣服下水吧？"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHIRLEY_NPC_GEASS_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L27_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"응? 무슨 소리야? 따로 여벌 옷이 있는 것도 아닌데.","JPN":"え？　どういうこと？　着替えがあるわけでもないし。","ENG":"Huh? What do you mean? It's not like I have another set of clothes or anything.","TWN":"嗯？不然呢？我又沒有準備多的衣服。"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SHIRLEY_NPC_GEASS_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"SHIRLEY_NPC_GEASS_NULL","text":{"KOREA":"후후, 여벌 옷이 없다니 너야 말로 무슨 소리야?","JPN":"フフ、着替えがないだなんて。","ENG":"Ha ha, what do you mean you don't have a change of clothes?","TWN":"呵呵，什麼沒有多的衣服，你在說什麼？"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SHIRLEY_NPC_GEASS_NULL","face":"UNIT_LAUGH"}}}},{"id":"L30_1","type":"dialog","speaker":"SHIRLEY_NPC_GEASS_NULL","text":{"KOREA":"미소녀부터 관능적인 숙녀까지~! 여기는 수영부 카페라고?","JPN":"美少女からアダルティなお姉様まで！　ここはより取り見取りの水泳部カフェなんだよ？","ENG":"From pretty young girls to sexy mature women! This is the Swim Club Cafe!","TWN":"無論是清純美少女…或是性感大姊姊～！這裡可是游泳部咖啡廳欸！"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHIRLEY_NPC_GEASS_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_TADA"},{"id":"L31_1","type":"dialog","speaker":"SHIRLEY_NPC_GEASS_NULL","text":{"KOREA":"따라와, 미나. 수영부실에 가면 미나 몸에 꼭 맞는 수영복이 있을 거야!","JPN":"ついて来て、ミナ。部室に行けばミナにピッタリな水着があるはず！","ENG":"Follow me, Mina. I'm sure we have a swimsuit that fits you perfectly in our club room!","TWN":"你跟我來，游泳部裡一定有適合你身材的泳裝的！"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHIRLEY_NPC_GEASS_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};